124→export function recordAdjustmentEvent(
125→  input: RecordAdjustmentEventInput,
126→  tx?: DbOrTx,
127→) {
128→  const timestamp = now();
129→  const target = tx ?? db;
130→
131→  target
132→    .insert(adjustmentEvents)
133→    .values({
134→      id: crypto.randomUUID(),
135→      importId: input.importId,
136→      sessionId: input.sessionId ?? null,
137→      ruleId: input.ruleId ?? null,
138→      targetFormat: input.targetFormat,
139→      eventType: input.type,
140→      payloadJson:
141→        input.payload === undefined ? null : JSON.stringify(input.payload),
142→      createdAt: timestamp,
143→    })
144→    .run();
145→}
