147→export function createAdjustmentSession(input: CreateAdjustmentSessionInput): {
148→  session: AdjustmentSession;
149→  reused: boolean;
150→} {
151→  const existing = findReusableAdjustmentSession(input);
152→
153→  if (existing) {
154→    return { session: existing, reused: true };
155→  }
156→
157→  const timestamp = now();
158→  const session: AdjustmentSession = adjustmentSessionSchema.parse({
159→    id: crypto.randomUUID(),
160→    importId: input.importId,
161→    targetFormat: input.targetFormat,
162→    status: "open",
163→    selection: input.selection,
164→    createdAt: timestamp,
165→    updatedAt: timestamp,
166→  });
167→
168→  db.transaction((tx) => {
169→    tx.insert(adjustmentSessions)
170→      .values({
171→        id: session.id,
172→        importId: session.importId,
173→        targetFormat: session.targetFormat,
174→        status: session.status,
175→        selectionJson: JSON.stringify(session.selection),
176→        previewArtifactJson: null,
177→        createdAt: session.createdAt,
178→        updatedAt: session.updatedAt,
179→      })
180→      .run();
181→
182→    recordAdjustmentEvent(
183→      {
184→        importId: session.importId,
185→        sessionId: session.id,
186→        targetFormat: session.targetFormat,
187→        type: "session_created",
188→      },
189→      tx,
190→    );
191→  });
192→
193→  return { session, reused: false };
194→}
