226→export function findReusableAdjustmentSession(
227→  input: CreateAdjustmentSessionInput,
228→) {
229→  return listAdjustmentSessions(input.importId, input.targetFormat).find(
230→    (session) =>
231→      session.status === "open" &&
232→      selectionsMatch(session.selection, input.selection),
233→  );
