334→export function updateFormatRuleEffect(
335→  ruleId: string,
336→  effect: CustomStyleEffect,
337→  instruction?: string,
338→): FormatRule {
339→  const existingRule = getFormatRule(ruleId);
340→
341→  if (!existingRule) {
342→    throw new Error("Formatregel nicht gefunden.");
343→  }
344→
345→  const timestamp = now();
346→  const updates: Record<string, unknown> = {
347→    compiledRuleJson: JSON.stringify(effect),
348→    updatedAt: timestamp,
349→  };
350→
351→  if (instruction !== undefined) {
352→    updates.instruction = instruction;
353→  }
354→
355→  db.update(formatRules).set(updates).where(eq(formatRules.id, ruleId)).run();
356→
357→  const nextRule = getFormatRule(ruleId);
358→
359→  if (!nextRule) {
360→    throw new Error("Formatregel konnte nicht neu geladen werden.");
361→  }
362→
363→  return nextRule;
364→}
