537→type InputMessage = {
538→  content: Array<{ text: string; type: "input_text" | "output_text" }>;
539→  role: "system" | "user" | "assistant";
540→};
541→
542→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
543→  const targetFormat = input.sessionDetail.session.targetFormat;
544→  const messages: InputMessage[] = [
545→    {
546→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
547→      role: "system",
548→    },
549→    {
550→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
551→      role: "user",
552→    },
553→  ];
554→
555→  // Add session messages as real multi-turn conversation so the model
556→  // understands the full dialog history and can reference prior turns.
557→  for (const msg of input.sessionDetail.messages) {
558→    const role = msg.role === "user" ? "user" : "assistant";
559→    messages.push({
560→      content: [
561→        {
562→          text: msg.content,
563→          type: role === "assistant" ? "output_text" : "input_text",
564→        },
565→      ],
566→      role,
567→    });
568→  }
569→
570→  return messages;
571→}
