 99→    importId: row.importId,
100→    targetFormat: row.targetFormat,
101→    kind: row.kind,
102→    scope: row.scope,
103→    status: row.status,
104→    selector: parseJson<unknown>(row.selectorJson),
105→    instruction: row.instruction,
106→    compiledRule: parseJson<unknown>(row.compiledRuleJson),
107→    sourceSessionId: row.sourceSessionId ?? undefined,
