147→export function createAdjustmentSession(input: CreateAdjustmentSessionInput): {
148→  session: AdjustmentSession;
149→  reused: boolean;
150→} {
151→  const existing = findReusableAdjustmentSession(input);
152→
153→  if (existing) {
