206→export function listAdjustmentSessions(
207→  importId: string,
208→  targetFormat?: AdjustmentTargetFormat,
209→) {
210→  const conditions = [eq(adjustmentSessions.importId, importId)];
211→
212→  if (targetFormat) {
213→    conditions.push(eq(adjustmentSessions.targetFormat, targetFormat));
214→  }
215→
216→  const rows = db
217→    .select()
218→    .from(adjustmentSessions)
219→    .where(and(...conditions))
220→    .orderBy(desc(adjustmentSessions.createdAt))
221→    .all();
