418→
419→function blockToPlainText(block: Block) {
420→  switch (block.type) {
421→    case "paragraph":
422→    case "heading":
423→    case "quote":
424→    case "code":
425→      return block.text;
426→    case "list":
427→      return block.items.join("\n");
428→    case "table":
429→      return [
430→        block.headers.join(" | "),
431→        ...block.rows.map((row) => row.join(" | ")),
432→      ].join("\n");
433→  }
434→}
435→
436→function summarizeSelection(
437→  sessionDetail: AdjustmentSessionDetail,
438→  job: ImportJob | undefined,
439→) {
440→  const { selection, targetFormat } = sessionDetail.session;
441→
442→  if (targetFormat === "markdown") {
443→    const markdown = job?.artifacts?.markdown ?? "";
444→    const lines = markdown.split("\n");
445→    const lineStart = selection.lineStart ?? 1;
446→    const lineEnd = selection.lineEnd ?? lineStart;
447→
448→    return {
449→      currentExcerpt:
450→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
451→        selection.selectedText,
452→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
453→      surrounding: {
454→        next: lines[lineEnd] ?? null,
455→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
456→      },
457→    };
458→  }
459→
460→  const message = job?.conversation?.messages.find(
461→    (entry) => entry.id === selection.messageId,
462→  );
463→  const currentBlock = message?.blocks[selection.blockIndex];
464→  const previousBlock =
465→    selection.blockIndex > 0
466→      ? message?.blocks[selection.blockIndex - 1]
467→      : undefined;
468→  const nextBlock = message?.blocks[selection.blockIndex + 1];
469→
470→  return {
471→    currentExcerpt: currentBlock
472→      ? blockToPlainText(currentBlock)
473→      : selection.selectedText,
474→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
475→    surrounding: {
476→      next: nextBlock ? blockToPlainText(nextBlock) : null,
477→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
478→    },
479→  };
480→}
481→
482→function buildSelectionContext(input: RunAgentTurnInput) {
483→  const { activeRules, job, sessionDetail } = input;
484→  const { selection, targetFormat } = sessionDetail.session;
485→  const selectionContext = summarizeSelection(sessionDetail, job);
486→  const lines: string[] = [];
487→
488→  lines.push("## Ausgewählter Block");
489→  lines.push(`Format: ${targetFormat}`);
490→  lines.push(
491→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockId: "${selection.blockId ?? ""}", blockIndex: ${selection.blockIndex})`,
492→  );
493→  lines.push(
494→    `Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`,
495→  );
496→  if (selection.lineStart != null) {
497→    lines.push(
498→      `Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`,
499→    );
500→  }
501→  lines.push("");
502→  lines.push("Inhalt des ausgewählten Blocks:");
503→  lines.push("```");
504→  lines.push(selectionContext.currentExcerpt);
505→  lines.push("```");
506→
507→  if (selectionContext.surrounding.previous) {
508→    lines.push("");
509→    lines.push("Block davor:");
510→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
511→  }
512→  if (selectionContext.surrounding.next) {
513→    lines.push("");
514→    lines.push("Block danach:");
515→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
516→  }
517→
518→  const active = activeRules
519→    .filter((rule) => rule.status === "active")
520→    .slice(0, 8);
521→  if (active.length > 0) {
522→    lines.push("");
523→    lines.push("## Bereits aktive Regeln");
524→    for (const rule of active) {
525→      const selectorStr = rule.selector
526→        ? JSON.stringify(rule.selector)
527→        : "(kein Selektor)";
528→      lines.push(
529→        `- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`,
530→      );
531→    }
532→  }
533→
534→  return lines.join("\n");
535→}
536→
537→type InputMessage = {
538→  content: Array<{ text: string; type: "input_text" | "output_text" }>;
539→  role: "system" | "user" | "assistant";
540→};
541→
542→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
543→  const targetFormat = input.sessionDetail.session.targetFormat;
544→  const messages: InputMessage[] = [
545→    {
546→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
547→      role: "system",
548→    },
549→    {
550→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
551→      role: "user",
552→    },
553→  ];
554→
555→  // Add session messages as real multi-turn conversation so the model
556→  // understands the full dialog history and can reference prior turns.
557→  for (const msg of input.sessionDetail.messages) {
558→    const role = msg.role === "user" ? "user" : "assistant";
559→    messages.push({
560→      content: [
561→        {
562→          text: msg.content,
563→          type: role === "assistant" ? "output_text" : "input_text",
564→        },
565→      ],
566→      role,
567→    });
568→  }
569→
570→  return messages;
571→}
