      scope: "import_local",
      status: "active",
      selector: { strategy: "block_type", blockType: "paragraph" },
      instruction: "Default instruction",
      createdAt: "2026-03-08T12:00:00.000Z",
      updatedAt: "2026-03-08T12:00:00.000Z",
      ...overrides,
    };
  }

  test("returns empty string for empty event list", () => {
    const result = _internal.buildActionHistory([], []);

    expect(result).toBe("");
  });

  test("maps rule_applied events to rule description", () => {
    const rules = [
      createFormatRule({ id: "abc-123", instruction: "Liste weiter eingerückt" }),
      createFormatRule({ id: "def-456", instruction: "Überschrift kleiner" }),
    ];
    const events = [
      { eventType: "rule_applied", ruleId: "abc-123", createdAt: "2026-03-08T12:01:00.000Z" },
      { eventType: "rule_applied", ruleId: "def-456", createdAt: "2026-03-08T12:02:00.000Z" },
    ];

    const result = _internal.buildActionHistory(events, rules);

    expect(result).toContain("## Deine bisherigen Aktionen in dieser Session");
    expect(result).toContain('1. Regel erstellt: "Liste weiter eingerückt" (ID: abc-123)');
    expect(result).toContain('2. Regel erstellt: "Überschrift kleiner" (ID: def-456)');
  });

  test("maps rule_disabled events to deletion text", () => {
    const events = [
      { eventType: "rule_disabled", ruleId: "ghi-789", createdAt: "2026-03-08T12:03:00.000Z" },
    ];

    const result = _internal.buildActionHistory(events, []);

    expect(result).toContain("1. Regel gelöscht (ID: ghi-789)");
  });

  test("uses fallback text when rule_applied event has no matching rule", () => {
    const events = [
      { eventType: "rule_applied", ruleId: "unknown-id", createdAt: "2026-03-08T12:01:00.000Z" },
    ];

    const result = _internal.buildActionHistory(events, []);

    expect(result).toContain('1. Regel erstellt: "(unbekannte Regel)" (ID: unknown-id)');
  });

  test("correct numbering with mixed event types", () => {
    const rules = [
      createFormatRule({ id: "abc-123", instruction: "Liste weiter eingerückt" }),
    ];
    const events = [
      { eventType: "rule_applied", ruleId: "abc-123", createdAt: "2026-03-08T12:01:00.000Z" },
      { eventType: "rule_disabled", ruleId: "def-456", createdAt: "2026-03-08T12:02:00.000Z" },
      { eventType: "rule_applied", ruleId: "unknown", createdAt: "2026-03-08T12:03:00.000Z" },
    ];

    const result = _internal.buildActionHistory(events, rules);

    expect(result).toContain('1. Regel erstellt: "Liste weiter eingerückt" (ID: abc-123)');
    expect(result).toContain("2. Regel gelöscht (ID: def-456)");
    expect(result).toContain('3. Regel erstellt: "(unbekannte Regel)" (ID: unknown)');
  });
});

