602→// ---------------------------------------------------------------------------
603→// OpenAI helpers
604→// ---------------------------------------------------------------------------
605→
606→function isRecord(value: unknown): value is Record<string, unknown> {
607→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
608→}
609→
610→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
611→  if (!Array.isArray(payload.output)) {
612→    return [];
613→  }
614→
615→  return payload.output.flatMap((item) => {
616→    if (!isRecord(item) || item.type !== "function_call") {
617→      return [];
618→    }
619→
620→    const callId = typeof item.call_id === "string" ? item.call_id : null;
621→    const name = typeof item.name === "string" ? item.name : null;
622→    const args = typeof item.arguments === "string" ? item.arguments : null;
623→
624→    if (!callId || !name || !args) {
625→      return [];
626→    }
627→
628→    return [{ arguments: args, callId, name }];
629→  });
630→}
631→
632→function extractAssistantMessage(payload: ResponsesPayload) {
633→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
634→    return payload.output_text.trim();
635→  }
636→
637→  if (!Array.isArray(payload.output)) {
638→    return "";
639→  }
640→
641→  return payload.output
642→    .flatMap((item) => {
643→      if (
644→        !isRecord(item) ||
645→        item.type !== "message" ||
646→        item.role !== "assistant"
647→      ) {
648→        return [];
649→      }
650→
651→      const content = item.content;
652→      if (!Array.isArray(content)) {
653→        return [];
654→      }
655→
656→      return content.flatMap((entry) => {
657→        if (!isRecord(entry) || entry.type !== "output_text") {
658→          return [];
659→        }
660→
661→        return typeof entry.text === "string" && entry.text.trim()
662→          ? [entry.text.trim()]
663→          : [];
664→      });
665→    })
666→    .join("\n")
667→    .trim();
668→}
669→
670→async function requestOpenAiResponse(
671→  body: Record<string, unknown>,
672→  config: ReturnType<typeof readAdjustmentAiConfig>,
673→) {
674→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
675→    method: "POST",
676→    headers: {
677→      "Content-Type": "application/json",
678→      Authorization: `Bearer ${config.openai?.apiKey}`,
679→    },
680→    body: JSON.stringify({
681→      model: config.model,
682→      reasoning: { effort: "medium" },
683→      store: true,
684→      ...body,
685→    }),
686→    signal: AbortSignal.timeout(config.timeoutMs),
687→  });
688→
689→  if (!response.ok) {
690→    const errorText = await response.text();
691→    throw new AgentUnavailableError(
692→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
693→    );
694→  }
695→
696→  return (await response.json()) as ResponsesPayload;
697→}
