699→// ---------------------------------------------------------------------------
700→// Tool execution with validation
701→// ---------------------------------------------------------------------------
702→
703→function validateEffect(effect: unknown): {
704→  ok: boolean;
705→  data?: Record<string, unknown>;
706→  error?: string;
707→} {
708→  const result = customStyleEffectSchema.safeParse(effect);
709→  if (result.success) {
710→    return { ok: true, data: result.data as Record<string, unknown> };
711→  }
712→
713→  const issues = result.error.issues
714→    .map((i) => `${i.path.join(".")}: ${i.message}`)
715→    .join("; ");
716→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
717→}
718→
719→async function executeToolCall(
720→  call: FunctionCallItem,
721→  callbacks: RunAgentTurnInput["callbacks"],
722→  actions: ActionRecord[],
723→): Promise<string> {
724→  let args: Record<string, unknown>;
725→  try {
726→    args = JSON.parse(call.arguments) as Record<string, unknown>;
727→  } catch {
728→    return JSON.stringify({
729→      ok: false,
730→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
731→    });
732→  }
733→
734→  if (call.name === "create_rule") {
735→    const effectValidation = validateEffect(args.effect);
736→    if (!effectValidation.ok) {
737→      return JSON.stringify({ ok: false, error: effectValidation.error });
738→    }
739→
740→    try {
741→      const { ruleId } = await callbacks.onCreateRule({
742→        selector: args.selector as Record<string, unknown>,
743→        effect: effectValidation.data as Record<string, unknown>,
744→        description: String(args.description ?? ""),
745→      });
746→      actions.push({ type: "created", ruleId });
747→      return JSON.stringify({ ok: true, ruleId });
748→    } catch (error) {
749→      return JSON.stringify({
750→        ok: false,
751→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
752→      });
753→    }
754→  }
755→
756→  if (call.name === "update_rule") {
757→    const effectValidation = validateEffect(args.effect);
758→    if (!effectValidation.ok) {
759→      return JSON.stringify({ ok: false, error: effectValidation.error });
760→    }
761→
762→    const ruleId = String(args.ruleId ?? "");
763→
764→    try {
765→      await callbacks.onUpdateRule({
766→        ruleId,
767→        effect: effectValidation.data as Record<string, unknown>,
768→        description:
769→          typeof args.description === "string" ? args.description : undefined,
770→      });
771→      actions.push({ type: "updated", ruleId });
772→      return JSON.stringify({ ok: true, ruleId });
773→    } catch (error) {
774→      return JSON.stringify({
775→        ok: false,
776→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
777→      });
778→    }
779→  }
780→
781→  if (call.name === "delete_rule") {
782→    const ruleId = String(args.ruleId ?? "");
783→
784→    try {
785→      await callbacks.onDeleteRule(ruleId);
786→      actions.push({ type: "deleted", ruleId });
787→      return JSON.stringify({ ok: true, ruleId });
788→    } catch (error) {
789→      return JSON.stringify({
790→        ok: false,
791→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
792→      });
793→    }
794→  }
795→
796→  return JSON.stringify({
797→    ok: false,
798→    error: `Unbekannter Tool-Call: ${call.name}`,
799→  });
800→}
