802→// ---------------------------------------------------------------------------
803→// Main agent turn
804→// ---------------------------------------------------------------------------
805→
806→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
807→  assistantMessage: string;
808→  actions: ActionRecord[];
809→}> {
810→  const config = readAdjustmentAiConfig();
811→
812→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
813→    throw new AgentUnavailableError(
814→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
815→    );
816→  }
817→
818→  const actions: ActionRecord[] = [];
819→  const targetFormat = input.sessionDetail.session.targetFormat;
820→
821→  const inputMessages = buildInputMessages(input);
822→
823→  const isFirstTurn =
824→    input.sessionDetail.messages.filter((m) => m.role === "user").length <= 1;
825→
826→  let payload = await requestOpenAiResponse(
827→    {
828→      input: inputMessages,
829→      tool_choice: isFirstTurn ? "required" : "auto",
830→      tools: buildTools(targetFormat),
831→    },
832→    config,
833→  );
834→
835→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
836→    const functionCalls = extractFunctionCalls(payload);
837→    if (functionCalls.length === 0) {
838→      break;
839→    }
840→
841→    if (!payload.id) {
842→      throw new Error(
843→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
844→      );
845→    }
846→
847→    const toolOutputs = [];
848→
849→    for (const call of functionCalls) {
850→      const result = await executeToolCall(call, input.callbacks, actions);
851→      toolOutputs.push({
852→        type: "function_call_output",
853→        call_id: call.callId,
854→        output: result,
855→      });
856→    }
857→
858→    payload = await requestOpenAiResponse(
859→      {
860→        input: toolOutputs,
861→        previous_response_id: payload.id,
862→        tool_choice: "auto",
863→        tools: buildTools(targetFormat),
864→      },
865→      config,
866→    );
867→  }
868→
869→  const rawMessage = extractAssistantMessage(payload);
870→  let assistantMessage: string;
871→
872→  if (rawMessage) {
873→    if (actions.length === 0 && !rawMessage.includes("?")) {
874→      // AI claims success without tool call → use honest fallback
875→      assistantMessage =
876→        "Ich konnte die Änderung leider nicht umsetzen. Kannst du genauer beschreiben, was du ändern möchtest?";
877→    } else {
878→      assistantMessage = rawMessage;
879→    }
880→  } else if (actions.length > 0) {
881→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
882→  } else {
883→    // The AI returned no text and took no actions — retry once with an
884→    // explicit nudge so the user sees an actual question instead of a
885→    // generic placeholder.
886→    const retryPayload = await requestOpenAiResponse(
887→      {
888→        input: [
889→          ...inputMessages,
890→          {
891→            content: [
892→              {
893→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
894→                type: "input_text",
895→              },
896→            ],
897→            role: "user",
898→          },
899→        ],
900→        tool_choice: "none",
901→        tools: buildTools(targetFormat),
902→      },
903→      config,
904→    );
905→
906→    assistantMessage =
907→      extractAssistantMessage(retryPayload) ||
908→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
909→  }
910→
911→  return { assistantMessage, actions };
912→}
913→
914→/** @internal — exported for testing only */
915→export const _internal = {
916→  buildActionHistory,
917→  buildSelectorSchema,
918→  buildSystemPrompt,
919→};
920→

