  afterEach(() => {
    process.env = { ...originalEnv };
    globalThis.fetch = originalFetch;
  });

  test("AI calls create_rule with CSS effect → callback receives validated effect", async () => {
    setTestEnv();
    const callbacks = createCallbacks();

    const createRuleArgs = {
      selector: {
        strategy: "exact",
        messageId: "message-1",
        blockIndex: 0,
        blockType: "paragraph",
