    mockCreateClipboardImportJob.mockReturnValue(job);

    const result = await client.imports.createFromClipboard({
      plainText: "Hello world",
    });

    expect(result).toEqual(job);
    expect(mockImportFromClipboard).toHaveBeenCalledWith({
      html: undefined,
      plainText: "Hello world",
